CREATE TABLE metros (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, normalized_name text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE districts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, normalized_name text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE schools (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, normalized_name text NOT NULL, metro_id uuid REFERENCES metros(id) ON DELETE SET NULL, district_id uuid REFERENCES districts(id) ON DELETE SET NULL, uil_conference text, priority_tier text, archived_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX schools_name_index ON schools(normalized_name); CREATE INDEX schools_active_index ON schools(archived_at);
CREATE TABLE school_addresses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), school_id uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE, line1 text NOT NULL, city text, postal_code text, is_primary boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE school_contact_methods (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), school_id uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE, type text NOT NULL, value text NOT NULL, is_primary boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE tags (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, normalized_name text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE school_tags (school_id uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE, tag_id uuid NOT NULL REFERENCES tags(id) ON DELETE CASCADE, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(school_id, tag_id));
CREATE TABLE school_verifications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), school_id uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE, status text NOT NULL, confidence text, source text, verified_at timestamptz, review_due_at timestamptz, notes text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE directors (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), legal_name text NOT NULL, normalized_name text NOT NULL, preferred_name text, current_title text, archived_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX directors_name_index ON directors(normalized_name); CREATE INDEX directors_active_index ON directors(archived_at);
CREATE TABLE director_employments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), director_id uuid NOT NULL REFERENCES directors(id) ON DELETE RESTRICT, school_id uuid NOT NULL REFERENCES schools(id) ON DELETE RESTRICT, title text, start_date timestamptz, end_date timestamptz, is_current boolean NOT NULL DEFAULT true, verification_status text, source text, last_verified_at timestamptz, confidence text, notes text, created_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX director_employment_school_index ON director_employments(school_id); CREATE INDEX director_employment_director_index ON director_employments(director_id);
CREATE TABLE director_contact_methods (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), director_id uuid NOT NULL REFERENCES directors(id) ON DELETE CASCADE, type text NOT NULL, value text NOT NULL, is_primary boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE director_verifications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), director_id uuid NOT NULL REFERENCES directors(id) ON DELETE CASCADE, status text NOT NULL, confidence text, source text, verified_at timestamptz, review_due_at timestamptz, notes text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE director_interests (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), director_id uuid NOT NULL REFERENCES directors(id) ON DELETE CASCADE, status text NOT NULL, notes text, created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE director_opportunities (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), director_id uuid NOT NULL REFERENCES directors(id) ON DELETE CASCADE, type text NOT NULL, notes text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE import_field_provenance (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), proposal_id uuid NOT NULL REFERENCES import_proposals(id) ON DELETE RESTRICT, entity_type text NOT NULL, entity_id uuid NOT NULL, field_name text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(proposal_id, entity_type, entity_id, field_name));
